import SwiftUI

struct WorkoutsView: View { @EnvironmentObject private var state:AppState; @State private var show=false; @State private var selected:WorkoutPlan?; var body: some View { NavigationStack{ List{ Section("This week"){ ForEach(state.workouts){ workout in Button{selected=workout; show=true} label:{ VStack(alignment:.leading,spacing:8){ HStack{ Image(systemName:workout.status == .completed ? "checkmark.circle.fill":"circle").foregroundStyle(workout.status == .completed ? .green:ForgeTheme.accent); Text(workout.name).font(.headline).foregroundStyle(.primary) }; Text("\(workout.exercises.count) exercises • \(workout.estimatedMinutes) min • \(workout.focus)").font(.caption).foregroundStyle(.secondary); ForEach(workout.exercises.prefix(3)){ Text("• \($0.exercise.name) — \($0.sets) × \($0.reps)").font(.caption).foregroundStyle(.secondary) } }.padding(.vertical,8) } } } }.navigationTitle("Workouts").toolbar{ Button{state.regenerateWeeklyPlan()} label:{Image(systemName:"arrow.clockwise")} }.fullScreenCover(isPresented:$show){ WorkoutModeView(workout:selected ?? state.nextWorkout).environmentObject(state) } } } }
